// Java 26 - Structured concurrency (PREVIEW, --enable-preview)
// Learn: fork subtasks and join them as one unit, then read each result.
import java.util.concurrent.StructuredTaskScope;
import java.util.concurrent.StructuredTaskScope.Subtask;

static String findUser() { return "ada"; }
static int fetchOrder() { return 7; }

try (var scope = StructuredTaskScope.open()) {
    Subtask<String> user = scope.fork(() -> findUser()); // runs concurrently
    Subtask<Integer> order = scope.fork(() -> fetchOrder());
    scope.join();
    System.out.println(user.get() + " " + order.get());
}
